const { columnMap, unmapped, rows, domainDetection } = $input.first().json;

function isCleanNumber(val) {
  if (val === null || val === undefined || val === "") return false;
  return /^-?\d+(\.\d+)?$/.test(String(val).trim());
}
function toNum(val) {
  return isCleanNumber(val) ? parseFloat(val) : NaN;
}
function get(row, field) {
  const col = columnMap[field];
  return col ? row[col] : undefined;
}

// FIX: real calendar validation, not just format matching
function isValidDate(str) {
  const m = String(str).trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (!m) return false;
  const [, mo, d, y] = m.map(Number);
  const date = new Date(y, mo - 1, d);
  return date.getFullYear() === y && date.getMonth() === mo - 1 && date.getDate() === d;
}

let totalRevenue = 0, validCount = 0, missingQty = 0, missingPrice = 0, missingTotal = 0;
let categoryRevenue = {};
let categoryCount = {};
let rowsByCategory = {};
let statusCount = {};
let paymentMethodCount = {};
let seenOrderIds = {};
let duplicateOrderIds = [];
let totalMismatches = [];
let invalidDates = [];

rows.forEach((r, i) => {
  const rowNum = r.row_number || (i + 2);
  const qty   = toNum(get(r, 'quantity'));
  const price = toNum(get(r, 'price'));
  const total = toNum(get(r, 'total'));

  if (!isCleanNumber(get(r, 'quantity'))) missingQty++;
  if (!isCleanNumber(get(r, 'price')))    missingPrice++;
  if (!isCleanNumber(get(r, 'total')))    missingTotal++;

  if (!isNaN(total)) {
    totalRevenue += total;
    validCount++;
  }

  const cat = (get(r, 'category') || "").trim() || "Unknown";
  categoryRevenue[cat] = (categoryRevenue[cat] || 0) + (isNaN(total) ? 0 : total);
  categoryCount[cat]   = (categoryCount[cat] || 0) + 1;
  if (!rowsByCategory[cat]) rowsByCategory[cat] = [];
  rowsByCategory[cat].push(rowNum);

  const status = get(r, 'status') || "Unknown";
  statusCount[status] = (statusCount[status] || 0) + 1;

  const payment = get(r, 'paymentMethod') || "Unknown";
  paymentMethodCount[payment] = (paymentMethodCount[payment] || 0) + 1;

  const orderId = get(r, 'orderId');
  if (orderId) {
    if (seenOrderIds[orderId]) {
      duplicateOrderIds.push({ Order_ID: orderId, rows: [seenOrderIds[orderId], rowNum] });
    } else {
      seenOrderIds[orderId] = rowNum;
    }
  }

  if (!isNaN(qty) && !isNaN(price) && !isNaN(total)) {
    const expected = qty * price;
    if (Math.abs(expected - total) > 0.5) {
      totalMismatches.push({
        row: rowNum,
        quantity: qty,
        price: price,
        expectedTotal: Math.round(expected * 100) / 100,
        actualTotal: total
      });
    }
  }

  const dateVal = get(r, 'orderDate');
  if (dateVal && !isValidDate(dateVal)) {
    invalidDates.push({ row: rowNum, value: dateVal });
  }
});

Object.keys(categoryRevenue).forEach(k => {
  categoryRevenue[k] = Math.round(categoryRevenue[k] * 100) / 100;
});

// NEW: explicit deterministic flag for negative category revenue, so the LLM
// doesn't have to spot this itself by scanning the raw JSON dump
const negativeRevenueCategories = Object.entries(categoryRevenue)
  .filter(([, v]) => v < 0)
  .map(([cat, v]) => ({ category: cat, revenue: v, rows: rowsByCategory[cat] || [] }));

const rowLevelIssues = rows.map((r, i) => {
  const rowNum = r.row_number || (i + 2);
  const issues = [];
  const priceVal = String(get(r, 'price') ?? '');
  const qtyVal   = String(get(r, 'quantity') ?? '');
  const catVal   = get(r, 'category');

  if (priceVal.match(/[a-zA-Z]/)) issues.push("non-numeric Price: " + priceVal);
  if (qtyVal.match(/[a-zA-Z]/))   issues.push("non-numeric Quantity: " + qtyVal);
  if (toNum(get(r, 'quantity')) < 0) issues.push("negative Quantity: " + qtyVal);
  if (toNum(get(r, 'price')) < 0)    issues.push("negative Price: " + priceVal);
  if (!catVal || catVal.trim() === "") {
    issues.push("missing/invalid Category: " + catVal);
  }
  if (issues.length > 0) return { row: rowNum, issues };
  return null;
}).filter(Boolean);

const computedStats = {
  totalRecords: rows.length,
  validTotalRecords: validCount,
  missingOrInvalidQuantityCount: missingQty,
  missingOrInvalidPriceCount: missingPrice,
  missingOrInvalidTotalCount: missingTotal,
  totalRevenue: totalRevenue.toFixed(2),
  averageOrderValue: (totalRevenue / validCount).toFixed(2),
  revenueByCategory: categoryRevenue,
  categoryFrequency: categoryCount,
  rowsByCategory,
  negativeRevenueCategories,
  ordersByStatus: statusCount,
  paymentMethodDistribution: paymentMethodCount,
  duplicateOrderIdCount: duplicateOrderIds.length,
  duplicateOrderIds,
  totalMismatchCount: totalMismatches.length,
  totalMismatches,
  invalidDateCount: invalidDates.length,
  invalidDates,
  rowLevelIssues,
  columnMap,
  unmappedColumns: unmapped,
  domainDetection
};

return [{ json: { computedStats } }];

const validation = $input.first().json; // from "Validate Report" node
const firstAnalysis = validation.reportText;
const stats = $('Computed Stats').first().json.computedStats;

const verifyPrompt = `You are a quality-control reviewer. A deterministic code check has ALREADY verified row citations and required findings — do not re-derive these, just incorporate the results below.

DETERMINISTIC CHECK RESULTS (already verified by code, trust these completely):
Invalid row citations found in the Row(s) column: ${validation.invalidCitations.length ? validation.invalidCitations.join(', ') : 'none'}
Required findings missing from the report: ${validation.missingFindings.length ? validation.missingFindings.join(', ') : 'none'}

GROUND TRUTH STATISTICS (for checking derived-number plausibility and tag correctness only):
${JSON.stringify(stats, null, 2)}

Your job is narrower than a full row-citation check:
1. For each number tagged [verified], confirm it matches a value in the ground truth. Flag any mismatch as [ground truth: X] vs [report claim: Y].
2. For each number tagged [derived], confirm it's plausible from the ground truth and isn't a renamed verified stat.
3. Flag any number with no tag at all.
4. Flag unsupported qualitative claims and vague language without numbers.
Do NOT re-check row numbers in the Row(s) column — that has already been verified deterministically above; just incorporate those results into your verdict.

Respond with ONLY this JSON object, nothing else, no markdown fences:
{"verdict": "APPROVED" or "NEEDS_REVISION", "issues": ["short bullet describing each specific issue, empty array if none"]}

Analysis to review:
${firstAnalysis}`;

return [{
  json: {
    body: JSON.stringify({
      model: "mistral-small-latest",
      messages: [{ role: "user", content: verifyPrompt }]
    }),
    deterministicValid: validation.deterministicValid,
    invalidCitations: validation.invalidCitations,
    missingFindings: validation.missingFindings,
    firstAnalysis
  }
}];

const rows = $input.all().map(i => i.json);
const sample = rows[0];
const keys = Object.keys(sample);
function detect(patterns) {
  return keys.find(k => patterns.some(p => k.toLowerCase().includes(p))) || null;
}
const columnMap = {
  id:            detect(['id']),
  customerName:  detect(['customer', 'client', 'name']),
  orderId:       detect(['order_id', 'orderid', 'order id']),
  orderDate:     detect(['date']),
  product:       detect(['product', 'item', 'sku']),
  category:      detect(['category', 'cat', 'type', 'department']),
  quantity:      detect(['quantity', 'qty', 'units', 'count']),
  price:         detect(['price', 'unit_price', 'rate', 'cost']),
  paymentMethod: detect(['payment', 'pay_method', 'method']),
  status:        detect(['status', 'state', 'order_status']),
  total:         detect(['total', 'amount', 'revenue', 'subtotal']),
};
const critical = ['orderId', 'quantity', 'price', 'total', 'category', 'status'];
const unmapped = critical.filter(c => !columnMap[c]);

// FIX: singularize before casing, so "electronic"/"electronics"/"ELECTRONICS" collapse to one bucket
function normalizeCategory(raw) {
  if (raw === null || raw === undefined) return null;
  let c = raw.toString().trim().toLowerCase();
  if (c === '' || c === 'nan') return null;
  if (c.endsWith('ies')) c = c.slice(0, -3) + 'y';        // e.g. "accessories" -> "accessory"
  else if (c.endsWith('s') && c.length > 1) c = c.slice(0, -1); // "electronics" -> "electronic"
  return c.charAt(0).toUpperCase() + c.slice(1);
}

const categoryCol = columnMap.category;
const normalizedRows = rows.map(r => {
  if (categoryCol) {
    r[categoryCol] = normalizeCategory(r[categoryCol]);
  }
  return r;
});

// Domain detection (unchanged)
const domainScores = { sales: 0, inventory: 0, hr: 0, finance: 0, logistics: 0 };
if (columnMap.orderId)       domainScores.sales += 3;
if (columnMap.price)         domainScores.sales += 2;
if (columnMap.total)         domainScores.sales += 2;
if (columnMap.customerName)  domainScores.sales += 2;
if (columnMap.product)       domainScores.sales += 1;
if (columnMap.paymentMethod) domainScores.sales += 2;
if (columnMap.status)        domainScores.sales += 1;
if (columnMap.product)       domainScores.inventory += 2;
if (columnMap.quantity)      domainScores.inventory += 2;
if (columnMap.category)      domainScores.inventory += 1;
if (!columnMap.customerName) domainScores.inventory += 1;
if (!columnMap.orderId)      domainScores.inventory += 1;
const hrKeywords = ['employee', 'salary', 'department', 'hire', 'position', 'manager'];
hrKeywords.forEach(k => {
  if (keys.some(v => v.toLowerCase().includes(k))) domainScores.hr += 2;
});
const finKeywords = ['account', 'transaction', 'debit', 'credit', 'balance', 'invoice'];
finKeywords.forEach(k => {
  if (keys.some(v => v.toLowerCase().includes(k))) domainScores.finance += 2;
});
const logKeywords = ['shipment', 'tracking', 'carrier', 'warehouse', 'delivery', 'freight'];
logKeywords.forEach(k => {
  if (keys.some(v => v.toLowerCase().includes(k))) domainScores.logistics += 2;
});
const detectedDomain = Object.entries(domainScores).sort((a, b) => b[1] - a[1])[0][0];
const confidence = (() => {
  const scores = Object.values(domainScores);
  const max = Math.max(...scores);
  if (max >= 8) return 'high';
  if (max >= 4) return 'medium';
  return 'low';
})();
const domainHints = {
  sales:     "Focus on revenue trends, order statuses, payment methods, category performance, and customer order values.",
  inventory: "Focus on stock quantities, category distribution, product availability, and quantity anomalies.",
  hr:        "Focus on salary distribution, department headcount, tenure, and employee status.",
  finance:   "Focus on transaction volumes, account balances, debit/credit patterns, and anomalies.",
  logistics: "Focus on shipment statuses, delivery performance, carrier distribution, and tracking anomalies."
};
return [{
  json: {
    columnMap,
    unmapped,
    rows: normalizedRows,
    domainDetection: {
      detectedDomain,
      confidence,
      scores: domainScores,
      analysisHint: domainHints[detectedDomain]
    }
  }
}];

// Pull metadata from the "Critique" code node by name — NOT from $input,
// since $input here is the Critique HTTP response, which strips custom fields.
const critiqueMeta = $('Critique').first().json;
const firstAnalysis = critiqueMeta.firstAnalysis;
const stats = $('Computed Stats').first().json.computedStats;

let llmVerdict = { verdict: 'NEEDS_REVISION', issues: ['Could not parse critique JSON'] };
try {
  const raw = $json.choices[0].message.content;
  const cleaned = raw.replace(/```json|```/g, '').trim();
  llmVerdict = JSON.parse(cleaned);
} catch (e) {
  // fall through to forced revision below
}

const needsRevision = !critiqueMeta.deterministicValid || llmVerdict.verdict === 'NEEDS_REVISION';

if (!needsRevision) {
  return [{
    json: {
      body: JSON.stringify({
        model: 'mistral-small-latest',
        messages: [{ role: 'user', content: firstAnalysis }]
      }),
      verdict: 'APPROVED',
      finalReport: firstAnalysis
    }
  }];
}

const issuesList = [];
critiqueMeta.invalidCitations.forEach(function(n) {
  issuesList.push('Row ' + n + ' was cited in the Row(s) column but does not appear in the ground truth row data. Remove or correct it.');
});
critiqueMeta.missingFindings.forEach(function(f) {
  issuesList.push('The report must explicitly mention: ' + f + '.');
});
(llmVerdict.issues || []).forEach(function(i) {
  issuesList.push(i);
});

const issuesText = issuesList.map(function(i) { return '- ' + i; }).join('\n');

const revisionPrompt = 'You are a Senior Data Analyst. You wrote an analysis report that has been reviewed and flagged for revision.\n' +
'GROUND TRUTH STATISTICS (the only source of verified numbers):\n' + JSON.stringify(stats, null, 2) + '\n' +
'YOUR ORIGINAL REPORT:\n' + firstAnalysis + '\n' +
'CRITIQUE / ISSUES TO FIX:\n' + issuesText + '\n' +
'YOUR TASK:\n' +
'Rewrite the full report fixing every issue listed above.\n' +
'RULES:\n' +
'- Fix every issue listed above\n' +
'- Keep all correct sections exactly as they were\n' +
'- Every number from the ground truth must be tagged [verified]\n' +
'- Every number you calculate must be tagged [derived]\n' +
'- Do not add new information not supported by the ground truth\n' +
'- Maintain the same output format as the original report\n' +
'- Be specific. Name the exact duplicate Order IDs, mismatch rows, and invalid date values from the ground truth\n' +
'- Row(s) column entries must be specific row numbers taken directly from rowLevelIssues, duplicateOrderIds, invalidDates, or rowsByCategory in the ground truth. Never invent row numbers.\n\n' +
'OUTPUT FORMAT: Return the full corrected report only, no preamble.';

return [{
  json: {
    body: JSON.stringify({
      model: 'mistral-small-latest',
      messages: [{ role: 'user', content: revisionPrompt }]
    }),
    verdict: 'NEEDS REVISION'
  }
}];

// === VALIDATION CHECK (replaces the deleted IF node) ===
// Validate Revision now feeds directly into this node. If the report failed
// deterministic validation, throw a real error so n8n's built-in Error Trigger
// catches it. This is the only way to stop an invalid report from reaching
// stakeholders without a separate IF/branching node.
const validation = $input.first().json;

if (validation.finalValid === false) {
  throw new Error(
    'Report failed deterministic validation. ' +
    'Invalid row citations: ' + JSON.stringify(validation.invalidCitations) + '. ' +
    'Missing required findings: ' + JSON.stringify(validation.missingFindings)
  );
}

// reportContent now comes straight from Validate Revision's output,
// which already resolved whether to use the original or revised report.
const reportContent = validation.reportContent;

// === EVERYTHING BELOW IS YOUR EXISTING LOGIC, UNCHANGED ===
const stats = $('Computed Stats').first().json.computedStats;
const domainRaw = stats.domainDetection.detectedDomain;
const date = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

const domain = domainRaw.charAt(0).toUpperCase() + domainRaw.slice(1);
const verdict = 'REVISED & COMPLETED';
const totalRecords = stats.totalRecords;
const totalRevenue = stats.totalRevenue;
const title = `${domain} Data Quality Report: ${date}`;

const content = (reportContent || '')
  .replace(/\[verified\]/g, '')
  .replace(/\[derived\]/g, '')
  .replace(/`([^`]+)`/g, '$1')
  .replace(/\s+([.,;:])/g, '$1')
  .replace(/\$\s+/g, '$')
  .replace(/\r\n/g, '\n')
  .trim();

function mdToHtml(md) {
  const lines = md.split('\n');
  let html = '';
  let inTable = false;
  let tableRows = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (/^\|(.+)\|$/.test(line)) {
      const cells = line.split('|').filter(c => c.trim() !== '');
      if (cells.every(c => c.trim().match(/^[-:]+$/))) continue;
      if (!inTable) {
        inTable = true;
        tableRows = [];
      }
      tableRows.push(cells.map(c => c.trim()));
      continue;
    }

    if (inTable) {
      html += `<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:13px;border:1px solid #dde1e7;">`;
      tableRows.forEach((row, idx) => {
        if (idx === 0) {
          html += `<thead><tr>` + row.map(c => `<th style="padding:10px 12px;background:#4a90d9;color:white;text-align:left;font-family:Arial,sans-serif;font-weight:600;">${c}</th>`).join('') + `</tr></thead><tbody>`;
        } else {
          const bg = idx % 2 === 0 ? '#f9fbff' : '#ffffff';
          html += `<tr>` + row.map(c => `<td style="padding:8px 12px;border:1px solid #dde1e7;font-family:Arial,sans-serif;font-size:13px;background:${bg};">${c}</td>`).join('') + `</tr>`;
        }
      });
      html += `</tbody></table>`;
      inTable = false;
      tableRows = [];
    }

    if (/^# (.+)$/.test(line)) {
      html += `<h1 style="font-family:Georgia,serif;font-size:22px;color:#1a1a2e;border-bottom:2px solid #4a90d9;padding-bottom:8px;margin-top:36px;">${line.replace(/^# /, '')}</h1>`;
    } else if (/^## (.+)$/.test(line)) {
      html += `<h2 style="font-family:Georgia,serif;font-size:17px;color:#2c3e50;margin-top:24px;margin-bottom:6px;">${line.replace(/^## /, '')}</h2>`;
    } else if (/^### (.+)$/.test(line)) {
      html += `<h3 style="font-family:Arial,sans-serif;font-size:15px;color:#34495e;margin-top:16px;">${line.replace(/^### /, '')}</h3>`;
    } else if (/^\d+\. (.+)$/.test(line)) {
      const formatted = line.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
      html += `<p style="font-family:Arial,sans-serif;font-size:14px;color:#2c3e50;line-height:1.7;margin:6px 0 6px 20px;">${formatted}</p>`;
    } else if (/^- (.+)$/.test(line)) {
      html += `<li style="font-family:Arial,sans-serif;font-size:14px;color:#2c3e50;margin:4px 0 4px 20px;">${line.replace(/^- /, '')}</li>`;
    } else if (line.trim() !== '') {
      const formatted = line.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
      html += `<p style="font-family:Arial,sans-serif;font-size:14px;color:#2c3e50;line-height:1.7;margin:6px 0;">${formatted}</p>`;
    }
  }

  return html;
}

const verdictColor = '#2980b9';

const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="max-width:860px;margin:0 auto;padding:40px;background:#ffffff;font-family:Arial,sans-serif;">

  <div style="background:linear-gradient(135deg,#1a1a2e,#2c3e50);padding:32px 40px;border-radius:8px;margin-bottom:32px;">
    <p style="color:#a8d8ff;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin:0 0 8px;">Business Intelligence — Confidential</p>
    <h1 style="color:#ffffff;font-family:Georgia,serif;font-size:28px;margin:0 0 8px;">Data Quality & Business Analysis Report</h1>
    <p style="color:#cce5ff;font-size:14px;margin:0;">${domain} Dataset &nbsp;|&nbsp; ${date}</p>
  </div>

  <div style="display:flex;gap:16px;margin-bottom:32px;">
    <div style="flex:1;background:#f0f7ff;border-left:4px solid #4a90d9;padding:16px 20px;border-radius:4px;">
      <p style="font-size:11px;color:#7f8c8d;text-transform:uppercase;letter-spacing:1px;margin:0 0 4px;">Total Records</p>
      <p style="font-family:Georgia,serif;font-size:22px;color:#1a1a2e;font-weight:bold;margin:0;">${totalRecords}</p>
    </div>
    <div style="flex:1;background:#f0f7ff;border-left:4px solid #4a90d9;padding:16px 20px;border-radius:4px;">
      <p style="font-size:11px;color:#7f8c8d;text-transform:uppercase;letter-spacing:1px;margin:0 0 4px;">Total Revenue</p>
      <p style="font-family:Georgia,serif;font-size:22px;color:#1a1a2e;font-weight:bold;margin:0;">$${Number(totalRevenue).toLocaleString()}</p>
    </div>
    <div style="flex:1;background:#f0f7ff;border-left:4px solid #4a90d9;padding:16px 20px;border-radius:4px;">
      <p style="font-size:11px;color:#7f8c8d;text-transform:uppercase;letter-spacing:1px;margin:0 0 4px;">Dataset Type</p>
      <p style="font-family:Georgia,serif;font-size:22px;color:#1a1a2e;font-weight:bold;margin:0;">${domain}</p>
    </div>
    <div style="flex:1;background:#f0f7ff;border-left:4px solid ${verdictColor};padding:16px 20px;border-radius:4px;">
      <p style="font-size:11px;color:#7f8c8d;text-transform:uppercase;letter-spacing:1px;margin:0 0 4px;">QA Status</p>
      <p style="font-family:Georgia,serif;font-size:16px;color:${verdictColor};font-weight:bold;margin:0;">${verdict}</p>
    </div>
  </div>

  <div style="line-height:1.8;">
    ${mdToHtml(content)}
  </div>

  <div style="margin-top:48px;padding-top:20px;border-top:1px solid #dde1e7;text-align:center;">
    <p style="font-size:12px;color:#95a5a6;">
      Business Intelligence Division &nbsp;|&nbsp; ${date} &nbsp;|&nbsp; Confidential
    </p>
  </div>

</body>
</html>`;

const emailBody = `Hi,

Please find the latest data quality and business analysis report ready for your review.

────────────────────────────────
Dataset Type  : ${domain}
Total Records : ${totalRecords}
Total Revenue : $${Number(totalRevenue).toLocaleString()}
QA Status     : ${verdict}
Report Date   : ${date}
────────────────────────────────

Please do not hesitate to reach out if you have any questions or require further analysis.

Best regards,
Business Intelligence Team`;

return [{
  json: {
    htmlContent: html,
    emailBody,
    title
  }
}];

const reportText = $input.first().json.choices[0].message.content;
const stats = $('Computed Stats').first().json.computedStats;

// Build the authoritative set of row numbers the report is allowed to cite
const validRows = new Set();
stats.rowLevelIssues.forEach(r => validRows.add(r.row));
stats.duplicateOrderIds.forEach(d => d.rows.forEach(r => validRows.add(r)));
stats.totalMismatches.forEach(m => validRows.add(m.row));
stats.invalidDates.forEach(d => validRows.add(d.row));
Object.values(stats.rowsByCategory).forEach(rows => rows.forEach(r => validRows.add(r)));

// Extract every row number cited in the Data Quality Issues table's Row(s) column
const tableLines = reportText.split('\n').filter(l => /^\|.*\|$/.test(l));
const citedRows = new Set();
tableLines.slice(1).forEach(line => { // skip header row
  const firstCell = line.split('|')[1] || '';
  if (/^[\s,\d]+$/.test(firstCell.trim())) {
    (firstCell.match(/\d+/g) || []).forEach(n => citedRows.add(Number(n)));
  }
});

const invalidCitations = [...citedRows].filter(n => !validRows.has(n));

// Check that every "must mention" finding from ground truth actually appears
const missingFindings = [];
stats.duplicateOrderIds.forEach(d => {
  if (!reportText.includes(d.Order_ID)) missingFindings.push(`duplicate order ID ${d.Order_ID}`);
});
stats.totalMismatches.forEach(m => {
  if (!reportText.includes(String(m.row))) missingFindings.push(`mismatch at row ${m.row}`);
});
stats.invalidDates.forEach(d => {
  if (!reportText.includes(String(d.row))) missingFindings.push(`invalid date at row ${d.row}`);
});

const valid = invalidCitations.length === 0 && missingFindings.length === 0;

return [{
  json: {
    deterministicValid: valid,
    invalidCitations,
    missingFindings,
    reportText
  }
}];

const rawInput = $input.first().json;
const reportText = rawInput?.choices?.[0]?.message?.content || '';

if (!reportText) {
  throw new Error(
    'Validate Revision: no report text found in input. Input keys were: ' +
    Object.keys(rawInput || {}).join(', ')
  );
}

const stats = $('Computed Stats').first().json.computedStats;

const validRows = new Set();
stats.rowLevelIssues.forEach(r => validRows.add(r.row));
stats.duplicateOrderIds.forEach(d => d.rows.forEach(r => validRows.add(r)));
stats.totalMismatches.forEach(m => validRows.add(m.row));
stats.invalidDates.forEach(d => validRows.add(d.row));
Object.values(stats.rowsByCategory).forEach(rows => rows.forEach(r => validRows.add(r)));

const tableLines = reportText.split('\n').filter(l => /^\|.*\|$/.test(l));
const citedRows = new Set();
tableLines.slice(1).forEach(line => {
  const firstCell = line.split('|')[1] || '';
  if (/^[\s,\d]+$/.test(firstCell.trim())) {
    (firstCell.match(/\d+/g) || []).forEach(n => citedRows.add(Number(n)));
  }
});
const invalidCitations = [...citedRows].filter(n => !validRows.has(n));

const missingFindings = [];
stats.duplicateOrderIds.forEach(d => {
  if (!reportText.includes(d.Order_ID)) missingFindings.push(`duplicate order ID ${d.Order_ID}`);
});
stats.totalMismatches.forEach(m => {
  if (!reportText.includes(String(m.row))) missingFindings.push(`mismatch at row ${m.row}`);
});
stats.invalidDates.forEach(d => {
  if (!reportText.includes(String(d.row))) missingFindings.push(`invalid date at row ${d.row}`);
});

const finalValid = invalidCitations.length === 0 && missingFindings.length === 0;

return [{
  json: {
    finalValid,
    invalidCitations,
    missingFindings,
    reportContent: reportText
  }
}];

const input = $input.first().json;
return [{
  json: {
    ...input,
    attempt: 1,
    maxAttempts: 3
  }
}];

